// Game: Celeste 64 Demake
// Format: Standard
// Room: first-room — project-owned Milestone 2 test room
//
// Layout (Quake coords, Z-up, 1 unit = 0.02 port units):
//   Spawn platform: x=[-400,300]  y=[-200,200]  z=[0,32]
//   Dash gap:       x=[300,600]   (6 port-units)
//   Landing:        x=[600,900]   y=[-200,200]  z=[0,32]
//   Climb wall:     x=[900,932]   y=[-16,16]    z=[32,400]
//   Kill walkway:   x=[600,900]   y=[200,240]   z=[0,16]
//   Strawberry:     at (750, -250, 64)
//
// Brush face convention (matching OG 1-1):
//   Left(xmin):  (xmin,ymin,zmin) (xmin,ymax,zmin) (xmin,ymin,zmax) → normal (+1,0,0) → x >= xmin
//   Right(xmax): (xmax,ymin,zmax) (xmax,ymax,zmax) (xmax,ymin,zmin) → normal (-1,0,0) → x <= xmax
//   Back(ymin):  (xmax,ymin,zmin) (xmin,ymin,zmin) (xmax,ymin,zmax) → normal (0,+1,0) → y >= ymin
//   Front(ymax): (xmin,ymax,zmin) (xmax,ymax,zmin) (xmin,ymax,zmax) → normal (0,-1,0) → y <= ymax
//   Bottom(zmin):(xmin,ymin,zmin) (xmax,ymin,zmin) (xmin,ymax,zmin) → normal (0,0,+1) → z >= zmin
//   Top(zmax):   (xmin,ymax,zmax) (xmax,ymax,zmax) (xmin,ymin,zmax) → normal (0,0,-1) → z <= zmax
//
